#include <stdio.h>
#include <stdlib.h>
#include <inttypes.h>

int cmp_int(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return (x > y) - (x < y);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int *a = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        qsort(a, N, sizeof(int), cmp_int);
        int64_t ans = 0;
        for (int i = 0; i < N; ++i) {
            int lo = i + 1, hi = N, pos = N;
            while (lo < hi) {
                int mid = lo + (hi - lo) / 2;
                if ((int64_t)a[mid] - a[i] >= K) {
                    pos = mid;
                    hi = mid;
                } else {
                    lo = mid + 1;
                }
            }
            ans += (int64_t)N - pos;
        }
        printf("%" PRId64 "\n", ans);
        free(a);
    }
    return 0;
}

