import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it); K = next(it)
        a = [next(it) for _ in range(N)]
        a.sort()
        ans = 0
        for i in range(N):
            lo, hi = i + 1, N
            while lo < hi:
                mid = (lo + hi) // 2
                if a[mid] - a[i] >= K:
                    hi = mid
                else:
                    lo = mid + 1
            ans += N - lo
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

